INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(75,replace('-- Create track_likes table if it doesn''t exist\nCREATE TABLE IF NOT EXISTS track_likes (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  track_id INTEGER NOT NULL,\n  wallet_address TEXT,\n  user_id TEXT,\n  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Now create the unique indexes\nCREATE UNIQUE INDEX IF NOT EXISTS idx_track_likes_unique ON track_likes(track_id, wallet_address) WHERE wallet_address IS NOT NULL;\nCREATE UNIQUE INDEX IF NOT EXISTS idx_track_likes_user_unique ON track_likes(track_id, user_id) WHERE user_id IS NOT NULL;\n\n-- Admin update\nUPDATE user_wallets SET is_admin = 1 WHERE id = 1;','\n',char(10)),replace('UPDATE user_wallets SET is_admin = 0 WHERE id = 1;\nDROP INDEX IF EXISTS idx_track_likes_user_unique;\nDROP INDEX IF EXISTS idx_track_likes_unique;\nDROP TABLE IF EXISTS track_likes;','\n',char(10)),'2026-03-10 05:29:23');
