INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(85,replace('-- Add payment queue status to track_reviews\nALTER TABLE track_reviews ADD COLUMN payment_status TEXT DEFAULT ''pending'';\n\n-- Create a simple lock table for payment processing\nCREATE TABLE payment_processing_lock (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  lock_key TEXT NOT NULL UNIQUE,\n  locked_at DATETIME,\n  locked_by TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Insert the single lock row for review payments\nINSERT INTO payment_processing_lock (lock_key, locked_at, locked_by) VALUES (''review_payments'', NULL, NULL);','\n',char(10)),replace('DELETE FROM payment_processing_lock WHERE lock_key = ''review_payments'';\nDROP TABLE payment_processing_lock;\nALTER TABLE track_reviews DROP COLUMN payment_status;','\n',char(10)),'2026-03-16 16:51:01');
