INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(104,replace('\n-- Add fractionalization columns to tracks table\nALTER TABLE tracks ADD COLUMN is_fractionalized INTEGER DEFAULT 0;\nALTER TABLE tracks ADD COLUMN locked_at DATETIME;\nALTER TABLE tracks ADD COLUMN fractional_percentage_sold REAL DEFAULT 0;\nALTER TABLE tracks ADD COLUMN total_shares INTEGER DEFAULT 0;\nALTER TABLE tracks ADD COLUMN krc20_ticker TEXT;\nALTER TABLE tracks ADD COLUMN krc20_deploy_txid TEXT;\nALTER TABLE tracks ADD COLUMN shares_sold INTEGER DEFAULT 0;\n\n-- Table for investor holdings\nCREATE TABLE track_shares (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    track_id INTEGER NOT NULL,\n    owner_address TEXT NOT NULL,\n    ticker TEXT NOT NULL,\n    shares_owned INTEGER NOT NULL,\n    purchase_price_kas TEXT,\n    purchased_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Indexes for fast lookups\nCREATE INDEX idx_tracks_fractionalized ON tracks(is_fractionalized);\nCREATE INDEX idx_track_shares_owner ON track_shares(owner_address, ticker);\nCREATE INDEX idx_track_shares_track ON track_shares(track_id);\nCREATE INDEX idx_tracks_ticker ON tracks(krc20_ticker);\n','\n',char(10)),replace('\nDROP INDEX IF EXISTS idx_tracks_ticker;\nDROP INDEX IF EXISTS idx_track_shares_track;\nDROP INDEX IF EXISTS idx_track_shares_owner;\nDROP INDEX IF EXISTS idx_tracks_fractionalized;\nDROP TABLE IF EXISTS track_shares;\n\nALTER TABLE tracks DROP COLUMN shares_sold;\nALTER TABLE tracks DROP COLUMN krc20_deploy_txid;\nALTER TABLE tracks DROP COLUMN krc20_ticker;\nALTER TABLE tracks DROP COLUMN total_shares;\nALTER TABLE tracks DROP COLUMN fractional_percentage_sold;\nALTER TABLE tracks DROP COLUMN locked_at;\nALTER TABLE tracks DROP COLUMN is_fractionalized;\n','\n',char(10)),'2026-04-22 13:38:52');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(105,replace('CREATE INDEX IF NOT EXISTS idx_track_shares_owner ON track_shares(owner_address);\nCREATE INDEX IF NOT EXISTS idx_track_shares_ticker ON track_shares(ticker);\nCREATE INDEX IF NOT EXISTS idx_track_shares_track ON track_shares(track_id);','\n',char(10)),replace('DROP INDEX IF EXISTS idx_track_shares_owner;\nDROP INDEX IF EXISTS idx_track_shares_ticker;\nDROP INDEX IF EXISTS idx_track_shares_track;','\n',char(10)),'2026-04-22 13:38:52');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(106,replace('ALTER TABLE tracks ADD COLUMN audio_hash TEXT;\nCREATE INDEX idx_tracks_audio_hash ON tracks(audio_hash);','\n',char(10)),replace('DROP INDEX idx_tracks_audio_hash;\nALTER TABLE tracks DROP COLUMN audio_hash;','\n',char(10)),'2026-04-22 13:38:52');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(107,replace('CREATE TABLE shareholder_payouts (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  track_id INTEGER NOT NULL,\n  recipient_address TEXT NOT NULL,\n  shares_at_time INTEGER NOT NULL,\n  total_shares_at_time INTEGER NOT NULL,\n  amount_kas TEXT NOT NULL,\n  source_payment_type TEXT,\n  source_transaction_id TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_shareholder_payouts_track ON shareholder_payouts(track_id);\nCREATE INDEX idx_shareholder_payouts_recipient ON shareholder_payouts(recipient_address);\nCREATE INDEX idx_shareholder_payouts_created ON shareholder_payouts(created_at);','\n',char(10)),replace('DROP INDEX IF EXISTS idx_shareholder_payouts_created;\nDROP INDEX IF EXISTS idx_shareholder_payouts_recipient;\nDROP INDEX IF EXISTS idx_shareholder_payouts_track;\nDROP TABLE IF EXISTS shareholder_payouts;','\n',char(10)),'2026-04-22 13:38:53');
