INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(109,replace('CREATE TABLE super_reacts (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    track_id INTEGER NOT NULL,\n    user_address TEXT NOT NULL,\n    amount_kas REAL NOT NULL,\n    comment_text TEXT NOT NULL,\n    is_anonymous INTEGER DEFAULT 0,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_super_reacts_track ON super_reacts(track_id);\nCREATE INDEX idx_super_reacts_amount ON super_reacts(track_id, amount_kas DESC);','\n',char(10)),replace('DROP INDEX IF EXISTS idx_super_reacts_amount;\nDROP INDEX IF EXISTS idx_super_reacts_track;\nDROP TABLE IF EXISTS super_reacts;','\n',char(10)),'2026-04-22 13:38:53');
