INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(114,replace('\n-- Add USD pricing to membership tiers\nALTER TABLE membership_tiers ADD COLUMN price_usd REAL;\n\n-- Cache for Kaspa exchange rate\nCREATE TABLE kaspa_price_cache (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  price_usd REAL NOT NULL,\n  source TEXT DEFAULT ''coingecko'',\n  fetched_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_kaspa_price_cache_fetched_at ON kaspa_price_cache(fetched_at DESC);\n','\n',char(10)),replace('\nDROP INDEX idx_kaspa_price_cache_fetched_at;\nDROP TABLE kaspa_price_cache;\nALTER TABLE membership_tiers DROP COLUMN price_usd;\n','\n',char(10)),'2026-04-23 22:39:21');
INSERT INTO "_mocha_migrations" ("number","up_sql","down_sql","applied_at") VALUES(115,replace('-- Make channel_id nullable to support users without channels\n-- SQLite doesn''t support ALTER COLUMN, so we need to recreate the table\n-- But that''s complex with foreign keys. Instead, we''ll just work around it\n-- by using a special value of -1 for user_id based views (different from 0)\n\n-- Create index on user_id for faster lookups\nCREATE INDEX IF NOT EXISTS idx_video_views_user_id ON video_views(user_id);\nCREATE INDEX IF NOT EXISTS idx_video_views_user_video ON video_views(user_id, video_id);','\n',char(10)),replace('DROP INDEX IF EXISTS idx_video_views_user_video;\nDROP INDEX IF EXISTS idx_video_views_user_id;','\n',char(10)),'2026-04-24 10:18:08');
