INSERT INTO "channels" ("id","wallet_address","name","handle","description","avatar_url","banner_url","subscriber_count","total_kas_earned","is_verified","created_at","updated_at","about","is_demo") VALUES(9,'kaspa:qq0es63uv8qyfvvry8pldlrnfzqyaqtl0v999hruzc3d2n3lev6xkz2e5mklg','Nerdy Games','nerdygames','Welcome to Nerdy Games — where logic beats luck. We solve Sudoku, conquer Minesweeper, and master brain games one puzzle at a time. 🧠✨','/api/kasshi/media/channels/9/avatar_1771787455168.png','/api/kasshi/media/channels/9/banner_1771787929573.jpg',4,'5.926',0,'2026-02-22 16:15:51','2026-03-30 16:53:08',replace('Welcome to Nerdy Games, the home of logic, strategy, and brain-powered fun.\n\nThis channel is dedicated to puzzle and learning games that challenge your thinking and sharpen your problem-solving skills. From solving tricky Sudoku grids to clearing intense Minesweeper boards, every video is about improving logic, spotting patterns, and thinking smarter.\n\nHere, we don’t just play games — we break them down.\nYou’ll find:\n\nStep-by-step Sudoku solving techniques\n\nMinesweeper strategy and logic breakdowns\n\nTips to improve speed and accuracy\n\nPattern recognition training\n\nBrain-boosting challenges\n\nOther classic and modern logic games\n\nWhether you’re a beginner learning the basics or someone trying to improve your speed and precision, this channel is built to help you level up your thinking.\n\nIf you love puzzles, numbers, strategy, and that satisfying “aha!” moment — you’re in the right place.\n\n🧠 New puzzles.\n🎮 Smart gameplay.\n🚀 Sharper thinking.\n\nSubscribe and train your brain.','\n',char(10)),0);
