INSERT INTO "videos" ("id","channel_id","title","description","video_url","thumbnail_url","duration_seconds","view_count","like_count","dislike_count","comment_count","kas_earned","status","created_at","updated_at","is_members_only","is_demo","is_private","public_id","price_kas","bunny_video_id","bunny_status","is_clip","crop_x","crop_y","crop_zoom") VALUES(17,11,'Kaspa Tribalism: Attacking Bitcoin Communities Road to Adoption? KAS influencers degrade BTC',replace('Bitcoin communities are tightly knit. There is a very large majority of them who are only interested in Bitcoin. The same goes for Kaspa. They have no space for other technologies as a strategy to get to the same, or similar result. \n\nEcosystem https://kasmi.online\nTelegram https://t.me/kasmiofficial\nX https://x.com/kasmi353\n\nSo who is right? Bitcoin? Kaspa? In what market is there ONE winner? imagine a world with Windows as the only operating system. How much pain do we put our own portfolios through by pushing only 1 narrative? \n\nIn this video, we do a dive in to how social media "influencers" go about spreading their gospel of Kaspa on X. We look at a few specific examples of people who strictly attack Bitcoin Maxis, relentlessly. Respect, Kindness, consideration all go out the window and Degradation dominates as Kaspians slam their point of view in BTC maxis timeline.','\n',char(10)),'/api/kasshi/media/videos/11/1771887827874.mp4','/api/kasshi/media/thumbnails/11/1771888670583.png',1345,17,3,0,1,'2.75500000','published','2026-02-23 23:17:51','2026-04-02 06:09:42',0,0,0,'y_WmfscPBwt','0.11',NULL,'pending',0,NULL,NULL,NULL);
