INSERT INTO "videos" ("id","channel_id","title","description","video_url","thumbnail_url","duration_seconds","view_count","like_count","dislike_count","comment_count","kas_earned","status","created_at","updated_at","is_members_only","is_demo","is_private","public_id","price_kas","bunny_video_id","bunny_status","is_clip","crop_x","crop_y","crop_zoom") VALUES(35,39,'The Dollar is Dying',replace('"The Dollar is Dying" is a hard-hitting hip-hop/reggae anthem, railing against the crumbling fiat system and flawed blockchains like Bitcoin, Solana, and Ethereum. Through gritty verses, the artist exposes central bank deceit, hyperinflation, and centralized control (e.g., Visa’s fees, CBDC dystopias), while championing Kaspa’s decentralized, scalable proof-of-work as the ultimate "sound money" solution. With sharp wordplay and crypto-specific jabs at whale manipulations and Ponzi-like tokens, the song’s infectious hook—“The dollar is dying, Bitcoin can’t scale, Gold is too heavy, Solana transactions fail”—rallies the Kaspa community, blending anti-establishment fervor with a hopeful vision of financial freedom, making it a viral rallying cry for crypto’s underdog rebels.\n\nCREDITS: "KAS TUNES"','\n',char(10)),'/api/kasshi/media/videos/39/1772207012263.mp4','/api/kasshi/media/thumbnails/39/1772207013884.jpg',216,51,3,0,2,'0.07600000','published','2026-02-27 15:43:35','2026-04-25 05:40:52',0,0,0,'EOD6EoPiLlb','0',NULL,'pending',0,NULL,NULL,NULL);
