INSERT INTO "videos" ("id","channel_id","title","description","video_url","thumbnail_url","duration_seconds","view_count","like_count","dislike_count","comment_count","kas_earned","status","created_at","updated_at","is_members_only","is_demo","is_private","public_id","price_kas","bunny_video_id","bunny_status","is_clip","crop_x","crop_y","crop_zoom") VALUES(40,41,'Kaspa Canonical',replace('Kaspa Canonical represents the evolution of the Kaspa network toward a more standardized, secure, and scalable architecture.\nIt focuses on refining the protocol to ensure consistent behavior across nodes, improving validation rules, and strengthening long-term network reliability.\n\nBy aligning implementations with a canonical (official and deterministic) structure, Kaspa enhances:\n\nNetwork efficiency through clearer consensus execution\n\nSecurity by reducing edge-case discrepancies between nodes\n\nScalability while maintaining its high-speed BlockDAG design\n\nDeveloper confidence with a predictable and unified protocol standard\n\nThis step is important because it moves Kaspa from rapid innovation toward maturity and infrastructure-grade stability, preparing the ecosystem for broader adoption, enterprise use cases, and more advanced applications built on top of its technology.','\n',char(10)),'https://vz-c0396511-d1e.b-cdn.net/e265fba1-3abb-4183-8d89-8f42b13c02d1/playlist.m3u8','/api/kasshi/media/thumbnails/41/1772220246605.jpg',302,1,0,0,0,'4.75000000','published','2026-02-27 19:24:07','2026-02-28 22:35:04',0,0,0,'s3xJC3UXTUQ','5','e265fba1-3abb-4183-8d89-8f42b13c02d1','finished',0,NULL,NULL,NULL);
INSERT INTO "videos" ("id","channel_id","title","description","video_url","thumbnail_url","duration_seconds","view_count","like_count","dislike_count","comment_count","kas_earned","status","created_at","updated_at","is_members_only","is_demo","is_private","public_id","price_kas","bunny_video_id","bunny_status","is_clip","crop_x","crop_y","crop_zoom") VALUES(41,41,'Kaspa upgrade - Covenants++',replace('The Covenants Upgrade is a major step forward for Kaspa, introducing programmable transaction constraints directly at the protocol level.\n\nCovenants allow transactions to define how funds can be spent in the future, enabling more advanced logic without sacrificing Kaspa’s speed or security. This unlocks powerful new capabilities such as:\n\nSecure vaults and recovery mechanisms to protect funds\n\nAdvanced escrow and conditional payments\n\nLayer-2 and smart contract–like constructions built natively on Kaspa\n\nImproved security models for institutions and large holders\n\nNew DeFi design space while keeping Kaspa’s scalable BlockDAG architecture\n\nUnlike traditional smart contracts, Covenants focus on predictable, enforceable spending rules, aligning with Kaspa’s philosophy of high performance, simplicity, and deterministic validation.\n\nThis upgrade moves Kaspa closer to becoming not just a fast payment network, but a programmable financial infrastructure capable of supporting complex applications at scale.','\n',char(10)),'https://vz-c0396511-d1e.b-cdn.net/05c58ffe-ddb3-4ec2-959c-ad6a4aac1505/playlist.m3u8','/api/kasshi/media/thumbnails/41/1772220438097.jpg',58,2,0,0,0,'0','published','2026-02-27 19:27:20','2026-04-01 18:01:51',0,0,0,'s-ee4b47Kic','0.5','05c58ffe-ddb3-4ec2-959c-ad6a4aac1505','finished',0,NULL,NULL,NULL);
