INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(2,0,NULL,'Dark Days Ahead or Good Things Coming?','Don''t Wanna Think About the World Anymore – Dive into this raw conscious rap anthem exposing fiat slavery, news psy-ops, tax-funded atrocities, and the rotten system crumbling in 2026. Red-pilled awakening bars: lose your fiat mind, grab the small axe, stack KAS with patience over panic, raise your voice against tyranny, and escape to freedom money.','/api/kasshi/media/music/audio/1772992701115-js0y3v.wav',NULL,NULL,'/api/kasshi/media/music/covers/1772992698139-c3i2ot.png',182,NULL,'Hip Hop',NULL,'0',22,0,1,'2026-03-08 17:58:22','2026-04-23 18:58:25',3,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(3,0,NULL,'The Dollar is Dying ',replace('"The Dollar is Dying" by Kas Tunes is a raw, punchy crypto anthem that hits like a wake-up call for anyone watching fiat currencies stumble. Clocking in around, this track blends hard-hitting hip-hop beats with reggae-infused vibes, delivering that perfect mix of urgency and laid-back defiance. Kas Tunes, the artist behind the Kaspa ecosystem-inspired music (think songs celebrating decentralization, speed, and real financial freedom), goes straight for the throat here. \n\nThe song calls out the slow-motion collapse of the US dollar, slams "flawed" blockchains like Bitcoin and Solana for not keeping up, and positions faster, more scalable alternatives (Kaspa) as the real future. Lyrics-wise, it''s unapologetic and meme-worthy — lines railing against inflation, central control, and dying fiat systems while shouting out the "real ones" who see what''s coming. It''s got that underground energy: not overproduced, just straight passion for sound money and blockchain truth. If you''re deep in crypto Twitter/X, especially the $KAS community, this one''s been circulating as a rally cry — short, catchy, and packs a message about why the old system''s on life support. Whether you''re stacking sats, KAS, or just tired of endless money printing, "The Dollar is Dying" feels like the soundtrack to the great monetary reset.\n\n','\n',char(10)),'/api/kasshi/media/music/audio/1773012146674-6ykcry.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773012143387-tjmevl.jpg',215,NULL,'Hip Hop',NULL,'0',8,0,1,'2026-03-08 23:22:29','2026-03-26 21:32:20',3,5,1,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(4,0,NULL,'Mind on my Kaspa','"Mind on My Kaspa" by Kas Tunes is a smooth, focused banger that locks in that relentless drive and laser-sharp conviction. Clocking in at around 3:30, this track fuses laid-back reggae undertones with crisp hip-hop delivery, creating a vibe that''s equal parts chill reflection and unshakeable confidence. The energy here is all about tunnel vision—finally discovering that one thing that''s truly calling, the speed, the freedom tech, eyes locked on the prize while the future accelerates ahead. It''s got those infectious hooks and rhythmic flow that make you nod along, repeating the mantra of keeping everything centered on what''s real and what''s next. Pure motivation wrapped in decentralized soul, with beats that hit just right for cruising, stacking, or just vibing deep in the ecosystem. If you''re tuned into the Kaspa rhythm, this one''s your daily affirmation: no distractions, no second-guessing, just forward motion and that unbreakable focus. Certified earworm for the community—turn it up and let it ride.','/api/kasshi/media/music/audio/1773012991972-m1ndz3.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773012989316-2dd8je.jpg',209,NULL,'Reggae',NULL,'0',7,0,1,'2026-03-08 23:36:33','2026-04-23 18:53:43',3,5,1,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(5,0,NULL,'Tax Piñatas','"Tax Piñatas" by Kas Tunes is a sharp, satirical rap cut that swings hard at the endless grind of taxes and government overreach, clocking in around 2:54 with that classic Kas Tunes blend of gritty hip-hop flow and subtle reggae echoes for a laid-back yet biting edge. The vibe is pure rebellion wrapped in fun imagery—picture swinging at bloated, candy-stuffed piñatas that represent the tax system, watching the "goodies" (your hard-earned cash) spill out to feed the machine while you keep building anyway. It''s got clever wordplay, punchy bars calling out the absurdity of it all, and an undercurrent of empowerment: keep stacking, keep creating, keep pushing through the noise because real value isn''t in the handouts or the takings—it''s in what you control. The beat drops heavy but groovy, perfect for head-nodding sessions or firing up the community when the fiat world''s feeling extra extractive. With subtitles on the video drop, it''s easy to catch every jab and smirk along. If you''re in the ecosystem and tired of the same old wealth transfers dressed up as policy, this track''s your anthem—smash the piñatas, keep the proof-of-community strong, and let the rhythm remind you why you''re here. Turn it loud and stay building. ','/api/kasshi/media/music/audio/1773014582004-o3uul4.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773014579310-mnod22.jpg',173,NULL,'Hip Hop',NULL,'0',5,0,1,'2026-03-09 00:03:04','2026-03-31 06:09:44',3,5,1,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(6,0,NULL,'Buyin the Dip','"Buyin'' the Dip" (Rap) by Kas Tunes is a high-energy, conviction-fueled banger that captures the pure grit and thrill of stacking during market chaos. Clocking in at around 2:15, this rap cut delivers sharp, rhythmic bars over punchy hip-hop production with those signature Kas Tunes undertones—crisp snares, deep bass, and just enough groove to keep it moving without losing the edge. The track''s all about that unbreakable mindset: red candles flashing, fear in the air, but you''re zooming out, ramen-fueled and battle-tested, loading up because the vision stays crystal clear. It''s got clever lines celebrating patience, diamond hands, and turning volatility into opportunity—pure crypto warrior energy wrapped in motivational flow. No fluff, just straight talk for the legends who buy when others panic, eat the dip for breakfast, and keep building toward the next level. The delivery is confident and infectious, with hooks that stick and make you want to replay it during every correction. Perfect for pumping yourself up before hitting that buy button, cruising the charts, or reminding the community why conviction beats FOMO every time. If you''re deep in the ecosystem and live for those discount moments, this one''s your battle cry—turn it up, stay focused, and keep buyin'' the dip like a boss.','/api/kasshi/media/music/audio/1773021660513-l3w13u.WAV',NULL,NULL,'/api/kasshi/media/music/covers/1773021658456-wtvy1w.jpg',134,NULL,'Hip Hop',NULL,'0',10,0,1,'2026-03-09 02:01:02','2026-04-16 07:12:23',3,5,1,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(7,0,NULL,'It''s lonely',replace('It’s lonely… it’s lonely at the top of the world\nCrown on my head, but my heart is a lonely boy\nSurrounded by millions, still searching for one real voice\nIt’s lonely… God, it’s lonely\nAnd I don’t know how to make the silence go away','\n',char(10)),'/api/kasshi/media/music/audio/1773060984091-hile0o.mp3',NULL,NULL,'/api/kasshi/media/music/covers/1773060979807-3eeuxt.jpg',260,NULL,'R&B',NULL,'0',10,0,1,'2026-03-09 12:56:29','2026-04-23 18:58:54',8,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(8,0,NULL,'deep funk (bang bang)','deep soul funk house (118-126 BPM)','/api/kasshi/media/music/audio/1773070812218-idot3u.WAV',NULL,NULL,'/api/kasshi/media/music/covers/1773070811634-gyjozs.jpg',1837,NULL,'House',NULL,'0',16,0,1,'2026-03-09 15:41:56','2026-04-14 20:47:54',6,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(9,0,NULL,'Last Dip with Mary Jane (kaspa)','"Last Dip with Mary Jane" by Kas Tunes is a gritty, nu-metal infused anthem that channels raw emotion and unyielding loyalty into one powerful ride. Clocking in around 2:29 (with a longer Degen Version variant out there), this track fuses heavy, angsty riffs and aggressive energy with hip-hop undertones, creating a sound that''s intense, cathartic, and perfectly tuned to the highs and lows of the crypto journey. Directly inspired by Tom Petty''s classic "Mary Jane''s Last Dance," Kas Tunes cleverly reimagines the iconic chorus and theme—personifying "Mary Jane" as that steadfast companion (here, a nod to Kaspa itself) who''s been ride-or-die through every storm. The lyrics paint a vivid picture of riding out what feels like the final big correction, holding tight, refusing to fold, because the connection runs deeper than any chart swing. It''s got that mix of frustration, passion, and defiant hope: screaming into the void while knowing the real one''s still by your side, ready for the rebound—echoing Petty''s timeless vibe of one last dance to kill the pain, but flipped into a crypto HODL saga of diamond hands and unbreakable faith.The production hits hard—distorted guitars clash with pounding drums and layered vocals that build to explosive choruses, giving it a nu-metal edge that''s rare in the crypto music space but feels right for those moments when the market tests your soul. Perfect for blasting when the red candles are screaming, reminding you why you got in and why you''re not leaving.If you''re in the ecosystem and have diamond-handed through the storms, this one''s your war cry and your love letter all in one—turn it up, feel the riffs, and remember: the last dip might just be the prelude to something massive. Stay locked in. ','/api/kasshi/media/music/audio/1773072411678-eysgkr.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773072408959-ioow7k.jpg',148,NULL,'Metal',NULL,'0',1,0,1,'2026-03-09 16:06:53','2026-03-31 06:19:33',3,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
