INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(11,0,NULL,'Kaspa Girl','"Kaspa Girl" by Kas Tunes is a smooth, heartfelt ode wrapped in upbeat hip-hop/reggae fusion vibes, clocking in around 4:02 with that signature Kas Tunes groove—laid-back rhythms, catchy flows, and just enough bounce to keep it replay-worthy. This one''s all about unwavering love and loyalty, flipping the crypto journey into a romantic metaphor: she''s the ride-or-die partner who''s been there through the volatility, the late nights watching charts, the doubts, and the triumphs. Lyrics paint her as resilient, trustworthy, built on that same fast, fair foundation—someone who grows with you, never sells out, and turns the hustle into shared wins. It''s got infectious hooks celebrating that deep connection, where trust runs as deep as the tech, and the future looks bright when you''re locked in together. The production blends crisp beats with melodic undertones, perfect for cruising, stacking, or just vibing with that special one who gets the vision. If you''re in the ecosystem and know what it means to hold strong beside someone real, this track hits different—pure appreciation, motivation, and feel-good energy rolled into one. Turn it up, let it play, and toast to the ones who stay through every block. ','/api/kasshi/media/music/audio/1773078803421-09bl9f.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773078788647-0arcem.jpg',241,NULL,'Reggae',NULL,'0',8,0,1,'2026-03-09 17:53:25','2026-04-15 02:41:30',3,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
