INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(21,0,NULL,'Long Views',replace('"Long Views" by Kas Tunes is a smooth, introspective hip-hop/reggae fusion that celebrates the power of patience and big-picture thinking. Clocking in around 2:20, this laid-back track delivers calm, confident energy: tune out the daily noise, red candles, and short-term panic—real winners zoom out, hold strong, and let time compound the vision. The lyrics capture that mental shift: from hourly stress to yearly conviction, seeing past fiat decay and legacy chain limitations toward scalable, decentralized sound money that quietly grows. The catchy, mantra-like chorus reinforces the core message—keep the long view, stay patient, trust the process. Crisp beats and subtle reggae grooves make it perfect for late-night reflections, chart sessions, or resetting your mindset after a volatile week.\n\nWhat you''ll get:\nReflective verses on mental resilience and ignoring short-term FUD\nInfectious chorus reminder: long views win every time\nBridge clarity hit: the future rewards are worth the pain','\n',char(10)),'/api/kasshi/media/music/audio/1773088577789-cqdtkq.WAV',NULL,NULL,'/api/kasshi/media/music/covers/1773088569672-ajlbgc.jpg',152,NULL,'Hip Hop',NULL,'0',5,0,1,'2026-03-09 20:36:20','2026-04-14 09:03:00',3,5,1,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(22,0,NULL,'Last Dip With Mary Jane (Degen)','"Last Dip with Mary Jane (Degen Version)" by Kas Tunes is the darker, heavier flip of the original—extended nu-metal rage that exposes the toxic chase for quick riches, hype traps, leverage burns, and endless degen plays that leave you broke and broken. Clocking in over 3:00, this cut twists Tom Petty''s "Mary Jane''s Last Dance" into a brutal warning: Mary Jane here is the seductive illusion of easy wins, the siren call that promises everything and delivers pain, regret, and empty wallets. Heavy distortion, crushing drums, screamed hooks, and aggressive flow build to explosive choruses that hit like a total wipeout—one last desperate dip, one more all-in gamble, one final dance before the lights crash out. It''s raw frustration and hard truth for anyone who''s chased the wrong highs and felt the fallout.','/api/kasshi/media/music/audio/1773100631286-of0fiw.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773100628127-1bdo61.jpg',201,NULL,'Metal',NULL,'0',7,0,1,'2026-03-09 23:57:13','2026-04-14 07:27:25',3,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
INSERT INTO "tracks" ("id","channel_id","album_id","title","description","audio_url","bunny_audio_id","bunny_status","cover_art_url","duration_seconds","track_number","genre","lyrics","price_kas","play_count","is_explicit","is_published","created_at","updated_at","music_profile_id","cached_avg_rating","cached_review_count","artist_name","beat_grid","bpm","is_fractionalized","locked_at","fractional_percentage_sold","total_shares","krc20_ticker","krc20_deploy_txid","shares_sold","audio_hash") VALUES(23,0,NULL,'Hyperinflate','"Hyperinflate" by Kas Tunes is a Chill trap/hip-hop banger flipping hyperinflation fears into Kaspa''s explosive breakout anthem. High-octane verses roast Bitcoin maxis ("bitcoin maxies close their eyes," "fought for freedom, now serve the beast with lies"), Lightning starvation, Wall Street paper control, network spam, and legacy fade—while hyping Kaspa''s 10 blocks/sec GHOSTDAG speed, pure PoW rebellion, and Satoshi''s real vision that "won''t fade, will not die in vain." Fiat evaporates, but Kaspa''s price & adoption moon as the tide turns, written in stars and charts. Pump-up for KAS holders battling FUD, maxis blocking truth, and anyone riding scalable sound money to victory.','/api/kasshi/media/music/audio/1773112686035-x6mj4t.wav',NULL,NULL,'/api/kasshi/media/music/covers/1773112683947-tqllys.jpg',144,NULL,'Hip Hop',NULL,'0',13,0,1,'2026-03-10 03:18:07','2026-04-14 21:15:54',3,NULL,0,NULL,NULL,NULL,0,NULL,0,0,NULL,NULL,0,NULL);
