, public_key TEXT, kaspay_username TEXT, encrypted_private_key TEXT, wallet_pin_hash TEXT, encrypted_mnemonic TEXT, demo_balance TEXT DEFAULT '0', totp_secret TEXT, is_totp_enabled INTEGER DEFAULT 0, extra_password_hash TEXT, is_extra_password_enabled INTEGER DEFAULT 0, has_viewed_mnemonic INTEGER DEFAULT 0, encrypted_password_mnemonic TEXT, require_password_on_login INTEGER DEFAULT 0, is_admin INTEGER DEFAULT 0);
CREATE TABLE user_settings (
