preferred_currency TEXT DEFAULT 'USD',
created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
, notifications_payments BOOLEAN DEFAULT 1, notifications_deposits BOOLEAN DEFAULT 1, notifications_marketing BOOLEAN DEFAULT 0, require_confirm_large BOOLEAN DEFAULT 1, large_payment_threshold TEXT DEFAULT '100', hide_balance BOOLEAN DEFAULT 0, compact_mode BOOLEAN DEFAULT 0, show_kas_amounts BOOLEAN DEFAULT 1, default_currency_send TEXT DEFAULT 'USD', auto_convert_to_kas BOOLEAN DEFAULT 1, theme TEXT DEFAULT 'default', app_password_hash TEXT, is_app_locked BOOLEAN DEFAULT 1, notifications_comments BOOLEAN DEFAULT 1);
