updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
, transfer_id TEXT, amount TEXT, fee_amount TEXT, receive_amount TEXT);
CREATE TABLE transactions (
id INTEGER PRIMARY KEY AUTOINCREMENT,
